INSERT INTO universe_bosses (name, description, boss_type, rarity, health_points, attack_power, defense, speed, abilities, weaknesses, resistances, loot_table, boss_reward, recommended_level, recommended_players, min_players) VALUES
('Derelict Commander', 'The ghostly AI of a destroyed command ship, still issuing orders to phantom crew.', 'arc', 'common', 10000, 150, 50, 35, '["Phantom Order", "Ghost Fleet", "Eerie Signal", "Hull Breach"]'::jsonb, '{"energy": 1.4}'::jsonb, '{"kinetic": 0.7}'::jsonb, '[{"item": "commander_log", "quantity": 1, "dropRate": 0.5}, {"item": "ghost_alloy", "quantity": 3, "dropRate": 0.4}]'::jsonb, '{"xp": 350, "credits": 800, "resources": {"metal": 150, "crystal": 80}}'::jsonb, 10, 1, 1),
('Asteroid Guardian', 'A massive crystalline organism protecting a rare mineral deposit in an asteroid belt.', 'arc', 'common', 12000, 130, 70, 25, '["Crystal Barrage", "Mineral Shield", "Rock Smash"]'::jsonb, '{"explosive": 1.5}'::jsonb, '{"kinetic": 0.5}'::jsonb, '[{"item": "guardian_crystal", "quantity": 2, "dropRate": 0.6}, {"item": "rare_mineral", "quantity": 5, "dropRate": 0.4}]'::jsonb, '{"xp": 400, "credits": 900, "resources": {"crystal": 200, "metal": 50}}'::jsonb, 12, 1, 1),
('Void Scout', 'A reconnaissance entity from the void dimensions, testing defenses before the main assault.', 'arc', 'common', 8000, 160, 30, 55, '["Void Probe", "Shadow Step", "Drain Beam"]'::jsonb, '{"kinetic": 1.6}'::jsonb, '{"energy": 0.5}'::jsonb, '[{"item": "void_data", "quantity": 1, "dropRate": 0.45}, {"item": "scout_device", "quantity": 1, "dropRate": 0.35}]'::jsonb, '{"xp": 300, "credits": 700, "resources": {"crystal": 100, "deuterium": 50}}'::jsonb, 10, 1, 1),
('Pirate Lieutenant', 'A mid-ranking pirate officer who has seized control of a small fleet of stolen ships.', 'arc', 'common', 11000, 140, 55, 40, '["Fleet Command", "Broadside", "Boarding Party"]'::jsonb, '{"explosive": 1.3}'::jsonb, '{"kinetic": 0.8}'::jsonb, '[{"item": "pirate_orders", "quantity": 1, "dropRate": 0.5}, {"item": "stolen_cargo", "quantity": 3, "dropRate": 0.5}]'::jsonb, '{"xp": 380, "credits": 1000, "resources": {"metal": 180, "crystal": 60}}'::jsonb, 12, 1, 1),
('Krell Outrider', 'An advanced scout of the Krell Dominion, gathering intelligence on new territories.', 'arc', 'common', 9500, 145, 45, 50, '["Bio Probe", "Krell Call", "Acid Spit"]'::jsonb, '{"energy": 1.5}'::jsonb, '{"kinetic": 0.6}'::jsonb, '[{"item": "krell_intel", "quantity": 1, "dropRate": 0.4}, {"item": "bio_sample", "quantity": 2, "dropRate": 0.5}]'::jsonb, '{"xp": 350, "credits": 850, "resources": {"metal": 120, "crystal": 80, "deuterium": 30}}'::jsonb, 11, 1, 1),
('Nebula Warden', 'A protector of a nebula ecosystem, hostile to all intruders regardless of intent.', 'arc', 'common', 13000, 120, 80, 20, '["Nebula Barrier", "Toxic Cloud", "Regeneration"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"energy": 0.6}'::jsonb, '[{"item": "nebula_core", "quantity": 1, "dropRate": 0.4}, {"item": "toxic_sample", "quantity": 3, "dropRate": 0.5}]'::jsonb, '{"xp": 420, "credits": 950, "resources": {"crystal": 180, "deuterium": 40}}'::jsonb, 14, 1, 1),
('Signal Phantom', 'An unidentified signal that has manifested as a hostile electronic entity.', 'arc', 'common', 7500, 170, 25, 60, '["Signal Jam", "Electronic Assault", "Phase Out"]'::jsonb, '{"kinetic": 1.7}'::jsonb, '{"energy": 0.4}'::jsonb, '[{"item": "signal_trace", "quantity": 1, "dropRate": 0.45}, {"item": "electronic_core", "quantity": 1, "dropRate": 0.35}]'::jsonb, '{"xp": 320, "credits": 750, "resources": {"crystal": 150, "deuterium": 60}}'::jsonb, 10, 1, 1),
('Salvage King', 'A rogue salvager who has booby-trapped an entire debris field to keep rivals out.', 'arc', 'common', 10500, 135, 60, 35, '["Trap Network", "Salvage Beam", "Debris Shield"]'::jsonb, '{"energy": 1.3}'::jsonb, '{"explosive": 0.8}'::jsonb, '[{"item": "salvage_map", "quantity": 1, "dropRate": 0.5}, {"item": "rare_part", "quantity": 2, "dropRate": 0.4}]'::jsonb, '{"xp": 370, "credits": 880, "resources": {"metal": 200, "crystal": 40}}'::jsonb, 13, 1, 1),
('Void Parasite', 'A void organism that attaches to ships and slowly consumes them from within.', 'arc', 'common', 8500, 155, 30, 50, '["Parasitic Attach", "Void Drain", "Leech Field"]'::jsonb, '{"kinetic": 1.5}'::jsonb, '{"energy": 0.5}'::jsonb, '[{"item": "parasite_sample", "quantity": 2, "dropRate": 0.5}, {"item": "void_tissue", "quantity": 3, "dropRate": 0.4}]'::jsonb, '{"xp": 330, "credits": 780, "resources": {"crystal": 120, "deuterium": 70}}'::jsonb, 11, 1, 1),
('Relic Hunter', 'A rival explorer who has claimed a powerful alien artifact and refuses to share.', 'arc', 'common', 11500, 140, 55, 40, '["Artifact Power", "Booby Trap", "Stolen Tech"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"kinetic": 0.7}'::jsonb, '[{"item": "alien_artifact", "quantity": 1, "dropRate": 0.3}, {"item": "hunter_map", "quantity": 1, "dropRate": 0.45}]'::jsonb, '{"xp": 400, "credits": 920, "resources": {"metal": 160, "crystal": 100}}'::jsonb, 13, 1, 1);
