('Krell Aberration', 'A Krell specimen that has mutated beyond control, possessing unpredictable abilities.', 'arc', 'mythic', 30000, 400, 130, 45, '["Mutation Burst", "Unpredictable Strike", "Bio Chaos", "Adaptive Form"]'::jsonb, '{"energy": 1.4}'::jsonb, '{"kinetic": 0.6, "explosive": 0.7}'::jsonb, '[{"item": "mutation_sample", "quantity": 2, "dropRate": 0.45}, {"item": "aberrant_core", "quantity": 1, "dropRate": 0.3}]'::jsonb, '{"xp": 1500, "credits": 4000, "resources": {"metal": 500, "crystal": 300, "deuterium": 100}}'::jsonb, 25, 2, 1),
