('Pirate Admiral', 'A high-ranking pirate commander leading a fleet of stolen warships against trade routes.', 'arc', 'mythic', 35000, 370, 150, 35, '["Fleet Command", "Broadside Barrage", "Boarding Assault", "Pirate Flag"]'::jsonb, '{"explosive": 1.3}'::jsonb, '{"kinetic": 0.7, "energy": 0.8}'::jsonb, '[{"item": "admiral_map", "quantity": 1, "dropRate": 0.3}, {"item": "stolen_weapons", "quantity": 3, "dropRate": 0.4}]'::jsonb, '{"xp": 1700, "credits": 4500, "resources": {"metal": 600, "crystal": 200, "deuterium": 80}}'::jsonb, 30, 2, 1),
('Nebula Titan', 'A massive organism that has evolved to live within nebulae, consuming cosmic radiation.', 'arc', 'mythic', 38000, 340, 170, 20, '["Nebula Crush", "Radiation Wave", "Cosmic Storm", "Regeneration"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"kinetic": 0.5, "energy": 0.6}'::jsonb, '[{"item": "titan_sample", "quantity": 2, "dropRate": 0.4}, {"item": "nebula_crystal", "quantity": 3, "dropRate": 0.35}]'::jsonb, '{"xp": 1800, "credits": 4800, "resources": {"crystal": 500, "deuterium": 200}}'::jsonb, 32, 2, 1),
('Void Warlord', 'A void entity that has conquered lesser void beings and now commands an army.', 'arc', 'mythic', 32000, 410, 120, 50, '["Void Army", "Shadow Strike", "Conqueror\'s Will", "Dimensional Rift"]'::jsonb, '{"kinetic": 1.4}'::jsonb, '{"energy": 0.5, "explosive": 0.7}'::jsonb, '[{"item": "warlord_seal", "quantity": 1, "dropRate": 0.3}, {"item": "void_conquest", "quantity": 2, "dropRate": 0.35}]'::jsonb, '{"xp": 1650, "credits": 4300, "resources": {"metal": 400, "crystal": 300, "deuterium": 130}}'::jsonb, 28, 2, 1),
