('Void Sovereign General', 'A void military leader commanding armies across multiple dimensions.', 'arc', 'rare', 95000, 850, 350, 45, '["Void Army Command", "Dimensional Assault", "Shadow Legion", "Void Fortress", "Strategic Withdrawal"]'::jsonb, '{"kinetic": 1.4}'::jsonb, '{"energy": 0.4, "explosive": 0.5}'::jsonb, '[{"item": "general_seal", "quantity": 1, "dropRate": 0.1}, {"item": "void_strategy", "quantity": 1, "dropRate": 0.15}, {"item": "dimension_map", "quantity": 2, "dropRate": 0.2}]'::jsonb, '{"xp": 5500, "credits": 16000, "resources": {"metal": 800, "crystal": 900, "deuterium": 500}}'::jsonb, 45, 3, 2),
