('Pirate Emperor', 'The supreme leader of all pirate factions, ruling from a hidden fortress in the galactic core.', 'arc', 'rare', 100000, 830, 380, 35, '["Pirate Empire", "Fleet Armada", "Stolen Arsenal", "Fortress Shield", "Emperor\'s Decree"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"kinetic": 0.5, "energy": 0.7}'::jsonb, '[{"item": "emperor_crown", "quantity": 1, "dropRate": 0.1}, {"item": "pirate_fortress_key", "quantity": 1, "dropRate": 0.15}, {"item": "stolen_relic", "quantity": 3, "dropRate": 0.25}]'::jsonb, '{"xp": 6000, "credits": 18000, "resources": {"metal": 1500, "crystal": 500, "deuterium": 300}}'::jsonb, 48, 4, 2),
('Cosmic Witness', 'An entity that has observed the birth and death of stars, accumulating vast knowledge and power.', 'arc', 'rare', 90000, 870, 320, 50, '["Cosmic Knowledge", "Star Memory", "Witness Beam", "Time Echo", "Ancient Wisdom"]'::jsonb, '{"kinetic": 1.4}'::jsonb, '{"energy": 0.3, "explosive": 0.5}'::jsonb, '[{"item": "witness_core", "quantity": 1, "dropRate": 0.1}, {"item": "star_memory", "quantity": 2, "dropRate": 0.2}, {"item": "cosmic_wisdom", "quantity": 1, "dropRate": 0.15}]'::jsonb, '{"xp": 5800, "credits": 16500, "resources": {"crystal": 1100, "deuterium": 500}}'::jsonb, 45, 3, 2),
('Krell Hive Matriarch', 'The biological mother of an entire Krell hive, controlling billions of offspring.', 'arc', 'rare', 110000, 800, 400, 25, '["Brood Command", "Spore Storm", "Regeneration", "Mother\'s Fury", "Hive Shield"]'::jsonb, '{"energy": 1.5}'::jsonb, '{"kinetic": 0.4, "explosive": 0.6}'::jsonb, '[{"item": "matriarch_heart", "quantity": 1, "dropRate": 0.1}, {"item": "hive_queen_egg", "quantity": 2, "dropRate": 0.18}, {"item": "krell_blood", "quantity": 4, "dropRate": 0.3}]'::jsonb, '{"xp": 6200, "credits": 17000, "resources": {"metal": 1200, "crystal": 600, "deuterium": 400}}'::jsonb, 48, 4, 2),
