('Void Serpent', 'A massive void organism that coils through dimensions, hunting cosmic prey.', 'arc', 'rare', 98000, 840, 360, 40, '["Void Coil", "Dimensional Strike", "Serpent\'s Fang", "Void Venom", "Regeneration"]'::jsonb, '{"kinetic": 1.4}'::jsonb, '{"energy": 0.4, "explosive": 0.6}'::jsonb, '[{"item": "serpent_fang", "quantity": 1, "dropRate": 0.1}, {"item": "void_venom", "quantity": 2, "dropRate": 0.2}, {"item": "serpent_scale", "quantity": 4, "dropRate": 0.3}]'::jsonb, '{"xp": 5700, "credits": 16500, "resources": {"metal": 900, "crystal": 900, "deuterium": 400}}'::jsonb, 46, 3, 2);
